	@Test
	void bindingProfileCapturesJointNdvsSketchesOverlapEvidenceAndEndpointMode() {
		StatementPattern pattern = pattern("s", "p", "o");
		pattern.setStringMetricPlanned("plannedPropertyPathEndpointMode", "fromStart");
		FiniteRelationEstimate finite = FiniteRelationEstimate.fromRows(List.of("s", "o"),
				List.of(List.of(iri("urn:test:s1"), iri("urn:test:o1")),
						List.of(iri("urn:test:s1"), iri("urn:test:o2"))),
				"test-finite");
		BagEstimate bag = new BagEstimate(2.0d, 2.0d, 0.0d, 1.0d, "test", Map.of("o",
				new VariableEstimate(2.0d, 2.0d, 0.0d, new TestSketch(2.0d))),
				Map.of(finite.variableSetKey(), finite), Map.of("optimizer.joinOverlapRows", 2.0d));

		BindingProfile profile = BindingProfile.fromBag(pattern, bag, Map.of("optimizer.coverageRows", 1.0d));

		assertEquals("fromStart", profile.endpointMode());
		assertTrue(profile.sketchVars().contains("o"));
		assertEquals(2.0d, profile.jointDistinctRows().get(VariableSetKey.of(List.of("s", "o"))), 0.0d);
		assertEquals(2.0d, profile.overlapEvidence().get("optimizer.joinOverlapRows"), 0.0d);
		assertEquals(1.0d, profile.overlapEvidence().get("optimizer.coverageRows"), 0.0d);
		assertTrue(profile.toBagEstimate(2.0d, 2.0d, 0.0d, 1.0d, "roundtrip", Map.of())
				.variable("o")
				.sketch() instanceof TestSketch);
	}

	@Test
	void bindingProfileMergeCombinesEmbeddedEvidenceProfiles() {
		DistributionSketch leftSketch = new TestSketch(10.0d);
		DistributionSketch rightSketch = new TestSketch(7.0d);
		BagEstimate leftBag = BagEstimate.exact(10.0d, "left-profile")
				.withVariable("leftOnly", new VariableEstimate(10.0d, 10.0d, 0.0d, leftSketch));
		BagEstimate rightBag = BagEstimate.exact(7.0d, "right-profile")
				.withVariable("rightOnly", new VariableEstimate(7.0d, 7.0d, 0.0d, rightSketch));
		BindingProfile left = BindingProfile.fromBag(null, leftBag, Map.of());
		BindingProfile right = BindingProfile.fromBag(null, rightBag, Map.of());

		BagEstimate merged = left.mergedWith(right)
				.toBagEstimate(17.0d, 17.0d, 0.0d, 1.0d, "merged", Map.of());

		assertSame(leftSketch, merged.variable("leftOnly").sketch(),
				"The left embedded profile must survive a BindingProfile merge");
		assertSame(rightSketch, merged.variable("rightOnly").sketch(),
				"The right embedded profile must survive a BindingProfile merge");
	}

	@Test
	void bindingProfileSatisfiesSeesCurrentProfileSketchKeys() {
		VariableSetKey key = VariableSetKey.of(Set.of("s", "o"));
		SketchEvidence evidence = new SketchEvidence(key, new TestSketch(10.0d), 10.0d, 10.0d,
				EvidenceQuality.TUPLE_SKETCH, "required-current");
		EvidenceProfile profile = new EvidenceProfile(10.0d, 10.0d, 0.0d, 1.0d, "required-current",
				Map.of("s", VariableEstimate.bound(10.0d, 10.0d),
						"o", VariableEstimate.bound(10.0d, 10.0d)),
				Map.of(), Map.of(key, evidence), Map.of(), Map.of());
		BindingProfile required = new BindingProfile(Map.of(), Map.of(), Map.of(), Map.of(), Set.of(), Map.of(),
				BindingProfile.ANY_ENDPOINT_MODE, profile);
		BindingProfile delivered = new BindingProfile(Map.of(), Map.of(), Map.of(), Map.of(), Set.of(), Map.of(),
				BindingProfile.ANY_ENDPOINT_MODE, profile);

		assertFalse(BindingProfile.ANY.satisfies(required),
				"An empty profile must not satisfy required current evidence carried only by EvidenceProfile");
		assertTrue(delivered.satisfies(required),
				"BindingProfile.satisfies must see embedded current EvidenceProfile sketch keys");
	}

